// ============================================================
// HydraNet - Engineers API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { checkEmailUniqueness, hashPassword, generateRandomPassword } from '@/lib/auth'
import { EntityStatus } from '@prisma/client'

// GET /api/engineers - List all engineers
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const dmaId = searchParams.get('dmaId')
    const branchId = searchParams.get('branchId')

    const engineers = await prisma.engineer.findMany({
      where: {
        ...(dmaId && { dmaId }),
        ...(branchId && { branchId }),
      },
      include: {
        branch: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
        team: { select: { id: true, name: true } },
        _count: { select: { reports: true } },
      },
      orderBy: { name: 'asc' },
    })

    const formattedEngineers = engineers.map((engineer) => ({
      ...engineer,
      branchName: engineer.branch.name,
      dmaName: engineer.dma.name,
      teamName: engineer.team?.name,
      assignedReports: engineer._count.reports,
    }))

    return NextResponse.json(formattedEngineers)
  } catch (error) {
    console.error('Error fetching engineers:', error)
    return NextResponse.json({ error: 'Failed to fetch engineers' }, { status: 500 })
  }
}

// POST /api/engineers - Create a new engineer
// Note: Role is always "engineer" by default. Team leaders are assigned via teams management.
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Check email uniqueness across all user tables
    const emailCheck = await checkEmailUniqueness(data.email)
    if (!emailCheck.isUnique) {
      return NextResponse.json(
        { error: `This email is already in use by a ${emailCheck.foundIn}` },
        { status: 400 }
      )
    }

    // Hash password or generate a random one if not provided
    const plainPassword = data.password || generateRandomPassword()
    const hashedPassword = await hashPassword(plainPassword)

    const engineer = await prisma.engineer.create({
      data: {
        name: data.name,
        email: data.email,
        password: hashedPassword,
        phone: data.phone || null,
        branchId: data.branchId,
        dmaId: data.dmaId,
        teamId: data.teamId || null,
        // Role is always "engineer" by default - team leaders are assigned via teams management
        status: data.status || 'active',
      },
      include: {
        branch: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
        team: { select: { id: true, name: true } },
      },
    })

    // Return engineer data along with generated password (if auto-generated)
    // In production, this should be sent via email instead
    const responseData = {
      ...engineer,
      branchName: engineer.branch.name,
      dmaName: engineer.dma.name,
      teamName: engineer.team?.name,
      // Only include generated password if it was auto-generated
      ...(data.password ? {} : { generatedPassword: plainPassword }),
    }

    return NextResponse.json(responseData, { status: 201 })
  } catch (error) {
    console.error('Error creating engineer:', error)
    // Return more detailed error message for debugging
    const errorMessage = error instanceof Error ? error.message : 'Failed to create engineer'
    return NextResponse.json({ error: errorMessage }, { status: 500 })
  }
}

// PUT /api/engineers - Update an engineer
// Note: Team assignment and role changes are done via teams management
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    if (!data.id) {
      return NextResponse.json({ error: 'Engineer ID is required' }, { status: 400 })
    }

    // Check email uniqueness across all user tables (excluding current engineer)
    if (data.email) {
      const emailCheck = await checkEmailUniqueness(data.email, data.id)
      if (!emailCheck.isUnique) {
        return NextResponse.json(
          { error: `This email is already in use by a ${emailCheck.foundIn}` },
          { status: 400 }
        )
      }
    }

    // Build update data
    const updateData: {
      name: string
      email: string
      phone: string | null
      branchId: string
      status: EntityStatus
      password?: string
    } = {
      name: data.name,
      email: data.email,
      phone: data.phone || null,
      branchId: data.branchId,
      status: data.status as EntityStatus,
    }

    // If password is provided, hash and update it
    if (data.password) {
      updateData.password = await hashPassword(data.password)
    }

    const engineer = await prisma.engineer.update({
      where: { id: data.id },
      data: updateData,
      include: {
        branch: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
        team: { select: { id: true, name: true } },
        _count: { select: { reports: true } },
      },
    })

    return NextResponse.json({
      ...engineer,
      branchName: engineer.branch.name,
      dmaName: engineer.dma.name,
      teamName: engineer.team?.name,
      assignedReports: engineer._count.reports,
    })
  } catch (error) {
    console.error('Error updating engineer:', error)
    return NextResponse.json({ error: 'Failed to update engineer' }, { status: 500 })
  }
}

// DELETE /api/engineers - Delete an engineer
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')

    if (!id) {
      return NextResponse.json({ error: 'Engineer ID is required' }, { status: 400 })
    }

    // Check if engineer exists
    const engineer = await prisma.engineer.findUnique({
      where: { id },
      include: {
        _count: { select: { reports: true } },
      },
    })

    if (!engineer) {
      return NextResponse.json({ error: 'Engineer not found' }, { status: 404 })
    }

    // If engineer is a team leader, remove the leaderId from their team
    if (engineer.role === 'team_leader') {
      await prisma.team.updateMany({
        where: { leaderId: id },
        data: { leaderId: null },
      })
    }

    // Delete the engineer (this will also remove them from any team)
    await prisma.engineer.delete({
      where: { id },
    })

    return NextResponse.json({ success: true, message: 'Engineer deleted successfully' })
  } catch (error) {
    console.error('Error deleting engineer:', error)
    return NextResponse.json({ error: 'Failed to delete engineer' }, { status: 500 })
  }
}
